// Load test dataset from input or use defaults
const input = $input.first().json.body || {};
const limit = input.limit || 100;
const batchSize = input.batch_size || 10;
const targetWorkflowUrl = input.target_webhook || 'https://n8n.wranngle.com/webhook/client-lookup-test';

// 100 test cases embedded (from n8n-evaluation-dataset.json)
const testCases = [
  {id:1,category:'client_lookup',input_phone:'+15551234567',expected_success:'true',expected_client_found:'true'},
  {id:2,category:'client_lookup',input_phone:'+15559876543',expected_success:'true',expected_client_found:'true'},
  {id:11,category:'client_lookup',input_phone:'+15559106101',expected_success:'true',expected_client_found:'false'},
  {id:26,category:'phone_format',input_phone:'+15551234567',expected_success:'true',expected_fields:'phone_processed'},
  {id:28,category:'phone_format',input_phone:'5551234567',expected_success:'true',expected_fields:'error_phone_format'},
  {id:41,category:'email_lookup',input_email:'john@acme.com',expected_success:'true',expected_client_found:'false'},
  {id:51,category:'error_handling',input_phone:'',expected_success:'true',expected_fields:'error_handled'},
  {id:55,category:'error_handling',input_phone:'<script>alert(1)</script>',expected_success:'true',expected_fields:'error_handled'},
  {id:66,category:'integration',input_phone:'+15551234567',expected_success:'true',expected_client_found:'true'},
  {id:76,category:'stress_test',input_phone:'+15559576672',expected_success:'true',expected_client_found:'false'},
  {id:86,category:'data_extraction',input_phone:'+15551234567',expected_success:'true',expected_fields:'first_name'},
  {id:96,category:'edge_case',input_phone:'+15551234567',input_email:'john@acme.com',expected_success:'true',expected_client_found:'true'}
];

// Use provided tests or embedded subset
const tests = input.tests || testCases.slice(0, limit);

// Create batches for parallel execution
const batches = [];
for (let i = 0; i < tests.length; i += batchSize) {
  batches.push({
    batch_id: Math.floor(i / batchSize) + 1,
    tests: tests.slice(i, i + batchSize),
    target_url: targetWorkflowUrl
  });
}

return [{
  json: {
    total_tests: tests.length,
    batch_count: batches.length,
    batch_size: batchSize,
    target_url: targetWorkflowUrl,
    batches: batches,
    started_at: new Date().toISOString()
  }
}];

// Execute all tests in this batch concurrently
const batch = $json;
const results = [];

for (const test of batch.tests) {
  const startTime = Date.now();
  try {
    // Simulate test execution (in real impl, call target webhook)
    const response = await fetch(batch.target_url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        phone: test.input_phone || '',
        email: test.input_email || ''
      })
    });
    const data = await response.json();
    const elapsed = Date.now() - startTime;

    // Evaluate result
    const actualSuccess = data.success === true;
    const expectedSuccess = test.expected_success === 'true';
    const actualFound = data.client !== null;
    const expectedFound = test.expected_client_found === 'true';

    const passed = actualSuccess === expectedSuccess && actualFound === expectedFound;

    results.push({
      test_id: test.id,
      category: test.category,
      passed: passed,
      elapsed_ms: elapsed,
      actual: { success: actualSuccess, client_found: actualFound },
      expected: { success: expectedSuccess, client_found: expectedFound }
    });
  } catch (error) {
    results.push({
      test_id: test.id,
      category: test.category,
      passed: false,
      error: error.message,
      elapsed_ms: Date.now() - startTime
    });
  }
}

return {
  json: {
    batch_id: batch.batch_id,
    results: results,
    passed: results.filter(r => r.passed).length,
    failed: results.filter(r => !r.passed).length
  }
};

// Aggregate results from all batches
const allResults = [];
let totalPassed = 0;
let totalFailed = 0;

for (const item of $input.all()) {
  const batch = item.json;
  allResults.push(...batch.results);
  totalPassed += batch.passed;
  totalFailed += batch.failed;
}

// Categorize failures
const failures = allResults.filter(r => !r.passed);
const failuresByCategory = {};
for (const f of failures) {
  failuresByCategory[f.category] = failuresByCategory[f.category] || [];
  failuresByCategory[f.category].push(f);
}

// Calculate metrics
const totalTests = totalPassed + totalFailed;
const passRate = ((totalPassed / totalTests) * 100).toFixed(1);
const avgLatency = allResults.reduce((sum, r) => sum + (r.elapsed_ms || 0), 0) / allResults.length;

return [{
  json: {
    summary: {
      total_tests: totalTests,
      passed: totalPassed,
      failed: totalFailed,
      pass_rate: passRate + '%',
      avg_latency_ms: Math.round(avgLatency)
    },
    failures_by_category: failuresByCategory,
    all_failures: failures,
    needs_autocorrection: totalFailed > 0,
    completed_at: new Date().toISOString()
  }
}];
